   1→import { useCallback, useEffect, useMemo, useState } from 'react';
   2→import { ActionPanel } from './components/action_panel/action_panel';
   3→import {
   4→  ClipboardHUDIcon,
   5→  createCopyAction,
   6→  performCopy,
   7→} from './components/action_panel/actions';
   8→import { Alert } from './components/alert/alert';
   9→import { CommandPalette } from './components/command_palette/command_palette';
  10→import { Detail } from './components/detail/detail';
  11→import { DetailMetadata } from './components/detail/detail_metadata';
  12→import { EmptyState } from './components/empty_state/empty_state';
  13→import { HUDContainer } from './components/hud/hud_container';
  14→import { CalculatorIcon, StarFilledIcon } from './components/icons';
  15→import { Kbd } from './components/kbd/kbd';
  16→import { List, ListItem, ListSection } from './components/list';
  17→import { QuickLook } from './components/quick_look/quick_look';
  18→import { SearchBar } from './components/search_bar/search_bar';
  19→import type { SearchDropdownSection } from './components/search_bar/search_dropdown';
  20→import { SearchDropdown } from './components/search_bar/search_dropdown';
  21→import { ToastContainer } from './components/toast/toast_container';
  22→import { useAlert } from './hooks/use_alert';
  23→import { useFavorites } from './hooks/use_favorites';
  24→import { useHUD } from './hooks/use_hud';
  25→import { useKeyboardShortcut } from './hooks/use_keyboard_shortcut';
  26→import {
  27→  NavigationContextProvider,
  28→  useNavigationStack,
  29→} from './hooks/use_navigation';
  30→import { useRecentCommands } from './hooks/use_recent_commands';
  31→import { useTheme } from './hooks/use_theme';
  32→import { useToast } from './hooks/use_toast';
  33→import { useWindow } from './hooks/use_window';
  34→import { getCommand, getSections, searchCommands } from './registry';
  35→import type { ListItemData, ListItemMetadataEntry, SectionData } from './types';
  36→import { evaluate } from './utils/calculator';
  37→import { fuzzyMatch } from './utils/fuzzy_search';
  38→
  39→type NavViewData =
  40→  | {
  41→      type: 'command';
  42→      commandId: string;
  43→    }
  44→  | {
  45→      type: 'detail';
  46→      item: ListItemData;
  47→    };
  48→
  49→const TRAY_COMMAND_MAP: Record<
  50→  string,
  51→  {
  52→    id: string;
  53→    name: string;
  54→  }
  55→> = {
  56→  clipboard: {
  57→    id: 'clipboard-history',
  58→    name: 'Clipboard History',
  59→  },
  60→  snippets: {
  61→    id: 'snippets',
  62→    name: 'Snippets',
  63→  },
  64→  settings: {
  65→    id: 'settings',
  66→    name: 'Settings',
  67→  },
  68→  about: {
  69→    id: 'settings',
  70→    name: 'Settings',
  71→  },
  72→  'check-updates': {
  73→    id: 'settings',
  74→    name: 'Settings',
  75→  },
  76→};
  77→
  78→function flattenItems(sections: SectionData[]): ListItemData[] {
  79→  return sections.flatMap(s => s.items);
  80→}
  81→
  82→function renderMetadataEntry(entry: ListItemMetadataEntry, index: number) {
  83→  switch (entry.type) {
  84→    case 'label':
  85→      return (
  86→        <DetailMetadata.Label
  87→          key={index}
  88→          title={entry.title}
  89→          text={entry.text}
  90→        />
  91→      );
  92→    case 'link':
  93→      return (
  94→        <DetailMetadata.Link
  95→          key={index}
  96→          title={entry.title}
  97→          text={entry.text}
  98→          target={entry.target}
  99→        />
 100→      );
 101→    case 'tag-list':
 102→      return (
 103→        <DetailMetadata.TagList key={index} title={entry.title}>
 104→          {entry.tags.map(tag => (
 105→            <DetailMetadata.Tag
 106→              key={tag.text}
 107→              text={tag.text}
 108→              color={tag.color}
 109→            />
 110→          ))}
 111→        </DetailMetadata.TagList>
 112→      );
 113→    case 'separator':
 114→      return <DetailMetadata.Separator key={index} />;
 115→  }
 116→}
 117→
 118→function SearchIcon() {
 119→  return (
 120→    <svg
 121→      width="48"
 122→      height="48"
 123→      viewBox="0 0 48 48"
 124→      fill="none"
 125→      xmlns="http://www.w3.org/2000/svg"
 126→    >
 127→      <circle cx="21" cy="21" r="12" stroke="currentColor" strokeWidth="3" />
 128→      <line
 129→        x1="30"
 130→        y1="30"
 131→        x2="42"
 132→        y2="42"
 133→        stroke="currentColor"
 134→        strokeWidth="3"
 135→        strokeLinecap="round"
 136→      />
 137→    </svg>
 138→  );
 139→}
 140→
 141→function DetailView({ item }: { item: ListItemData }) {
 142→  const itemDetail = item.detail;
 143→  if (!itemDetail) return null;
 144→  return (
 145→    <Detail
 146→      markdown={itemDetail.markdown}
 147→      metadata={
 148→        itemDetail.metadata ? (
 149→          <DetailMetadata>
 150→            {itemDetail.metadata.map(renderMetadataEntry)}
 151→          </DetailMetadata>
 152→        ) : undefined
 153→      }
 154→    />
 155→  );
 156→}
 157→
 158→export function App() {
 159→  useTheme();
 160→  const [query, setQuery] = useState('');
 161→  const [filterValue, setFilterValue] = useState('all');
 162→  const [selectedIndex, setSelectedIndex] = useState(0);
 163→  const [actionsOpen, setActionsOpen] = useState(false);
 164→  const [quickLookOpen, setQuickLookOpen] = useState(false);
 165→  const { toasts, show: showToast, hide: hideToast } = useToast();
 166→  const { items: hudItems, show: showHUD } = useHUD();
 167→  const { alertState, confirmAlert, dismiss: dismissAlert } = useAlert();
 168→  const nav = useNavigationStack<NavViewData>('Raycast');
 169→  const { push, popToRoot } = nav;
 170→  const { favoriteIds, isFavorite, toggleFavorite, moveFavorite } =
 171→    useFavorites();
 172→  const { recentIds, addRecent } = useRecentCommands();
 173→
 174→  const handleTrayNavigate = useCallback(
 175→    (target: string) => {
 176→      const mapping = TRAY_COMMAND_MAP[target];
 177→      if (!mapping) return;
 178→
 179→      const cmd = getCommand(mapping.id);
 180→      if (!cmd?.component) return;
 181→
 182→      popToRoot();
 183→      setQuery('');
 184→      setSelectedIndex(0);
 185→      setActionsOpen(false);
 186→      setQuickLookOpen(false);
 187→      setFilterValue('all');
 188→
 189→      addRecent(mapping.id);
 190→      push(mapping.name, {
 191→        type: 'command',
 192→        commandId: mapping.id,
 193→      });
 194→    },
 195→    [
 196→      push,
 197→      popToRoot,
 198→      addRecent,
 199→    ],
 200→  );
 201→
 202→  useWindow({
 203→    onShow: () => {
 204→      const input =
 205→        document.querySelector<HTMLInputElement>('.search-bar__input');
 206→      input?.focus();
 207→    },
 208→    onHide: () => {
 209→      setQuery('');
 210→      popToRoot();
 211→      setActionsOpen(false);
 212→      setQuickLookOpen(false);
 213→      setSelectedIndex(0);
 214→      setFilterValue('all');
 215→    },
 216→    onTrayNavigate: handleTrayNavigate,
 217→  });
 218→
 219→  const currentNavData = nav.currentEntry?.data;
 220→  const isRoot = !currentNavData;
 221→  const isFullView =
 222→    currentNavData?.type === 'command' &&
 223→    (getCommand(currentNavData.commandId)?.fullView ?? false);
 224→
 225→  const searchFilterSections: SearchDropdownSection[] = useMemo(
 226→    () => [
 227→      {
 228→        options: [
 229→          {
 230→            label: 'All',
 231→            value: 'all',
 232→          },
 233→        ],
 234→      },
 235→      {
 236→        title: 'Types',
 237→        options: [
 238→          {
 239→            label: 'Commands',
 240→            value: 'commands',
 241→          },
 242→          {
 243→            label: 'Applications',
 244→            value: 'applications',
 245→          },
 246→        ],
 247→      },
 248→    ],
 249→    [],
 250→  );
 251→
 252→  useEffect(() => {
 253→    if (nav.stackDepth === 0) {
 254→      setQuery('');
 255→      setFilterValue('all');
 256→      setSelectedIndex(0);
 257→      setActionsOpen(false);
 258→      setQuickLookOpen(false);
 259→    }
 260→  }, [nav.stackDepth]);
 261→
 262→  const registrySections = useMemo(() => getSections(), []);
 263→
 264→  const filtered = useMemo(() => {
 265→    let sections = registrySections;
 266→    if (filterValue === 'commands') {
 267→      sections = sections.filter(
 268→        s => s.title === 'Suggestions' || s.title === 'Commands',
 269→      );
 270→    } else if (filterValue === 'applications') {
 271→      sections = sections.filter(s => s.title === 'Applications');
 272→    }
 273→
 274→    const result = query ? searchCommands(query) : sections;
 275→
 276→    const filteredResult = query
 277→      ? result
 278→          .map(s => {
 279→            if (filterValue === 'commands') {
 280→              return s.title === 'Suggestions' || s.title === 'Commands'
 281→                ? s
 282→                : {
 283→                    ...s,
 284→                    items: [],
 285→                  };
 286→            }
 287→            if (filterValue === 'applications') {
 288→              return s.title === 'Applications'
 289→                ? s
 290→                : {
 291→                    ...s,
 292→                    items: [],
 293→                  };
 294→            }
 295→            return s;
 296→          })
 297→          .filter(s => s.items.length > 0)
 298→      : result;
 299→
 300→    const allFlatItems = registrySections.flatMap(s => s.items);
 301→    const favoriteItems = favoriteIds
 302→      .map(id => allFlatItems.find(item => item.id === id))
 303→      .filter((item): item is ListItemData => !!item);
 304→
 305→    if (query) {
 306→      const filteredFavs = favoriteItems.filter(
 307→        item =>
 308→          fuzzyMatch(query, item.title) ||
 309→          fuzzyMatch(query, item.subtitle ?? ''),
 310→      );
 311→      if (filteredFavs.length > 0) {
 312→        const favIds = new Set(filteredFavs.map(f => f.id));
 313→        const dedupedSections = filteredResult
 314→          .map(s => ({
 315→            ...s,
 316→            items: s.items.filter(item => !favIds.has(item.id)),
 317→          }))
 318→          .filter(s => s.items.length > 0);
 319→        return [
 320→          {
 321→            title: 'Favorites',
 322→            items: filteredFavs,
 323→          },
 324→          ...dedupedSections,
 325→        ];
 326→      }
 327→      return filteredResult;
 328→    }
 329→
 330→    const pinnedSections: SectionData[] = [];
 331→    const dedupIds = new Set<string>();
 332→
 333→    if (favoriteItems.length > 0) {
 334→      pinnedSections.push({
 335→        title: 'Favorites',
 336→        items: favoriteItems,
 337→      });
 338→      for (const item of favoriteItems) {
 339→        dedupIds.add(item.id);
 340→      }
 341→    }
 342→
 343→    const favSet = new Set(favoriteIds);
 344→    const recentItems = recentIds
 345→      .filter(id => !favSet.has(id))
 346→      .map(id => allFlatItems.find(item => item.id === id))
 347→      .filter((item): item is ListItemData => !!item);
 348→
 349→    if (recentItems.length > 0) {
 350→      pinnedSections.push({
 351→        title: 'Recent Commands',
 352→        items: recentItems,
 353→      });
 354→      for (const item of recentItems) {
 355→        dedupIds.add(item.id);
 356→      }
 357→    }
 358→
 359→    if (pinnedSections.length > 0) {
 360→      const dedupedSections = filteredResult
 361→        .map(s => ({
 362→          ...s,
 363→          items: s.items.filter(item => !dedupIds.has(item.id)),
 364→        }))
 365→        .filter(s => s.items.length > 0);
 366→      return [
 367→        ...pinnedSections,
 368→        ...dedupedSections,
 369→      ];
 370→    }
 371→
 372→    return filteredResult;
 373→  }, [
 374→    query,
 375→    filterValue,
 376→    favoriteIds,
 377→    recentIds,
 378→    registrySections,
 379→  ]);
 380→
 381→  const calculatorResult = useMemo(() => {
 382→    if (!isRoot || !query.trim()) return null;
 383→    return evaluate(query);
 384→  }, [
 385→    query,
 386→    isRoot,
 387→  ]);
 388→
 389→  const allItems = useMemo(() => {
 390→    const items = flattenItems(filtered);
 391→    if (calculatorResult) {
 392→      const calcItem: ListItemData = {
 393→        id: '__calculator__',
 394→        title: `= ${calculatorResult}`,
 395→        subtitle: query.trim(),
 396→        icon: <CalculatorIcon />,
 397→      };
 398→      return [
 399→        calcItem,
 400→        ...items,
 401→      ];
 402→    }
 403→    return items;
 404→  }, [
 405→    filtered,
 406→    calculatorResult,
 407→    query,
 408→  ]);
 409→
 410→  const selectedItem = isRoot ? allItems[selectedIndex] : undefined;
 411→
 412→  const handleQueryChange = useCallback((value: string) => {
 413→    setQuery(value);
 414→    setSelectedIndex(0);
 415→    setActionsOpen(false);
 416→  }, []);
 417→
 418→  const handleFilterChange = useCallback((value: string) => {
 419→    setFilterValue(value);
 420→    setSelectedIndex(0);
 421→  }, []);
 422→
 423→  const handleActiveIndexChange = useCallback((index: number) => {
 424→    setSelectedIndex(index);
 425→    setActionsOpen(false);
 426→  }, []);
 427→
 428→  const handleDrillIn = useCallback(() => {
 429→    const item = allItems[selectedIndex];
 430→    if (!item) return;
 431→
 432→    setActionsOpen(false);
 433→
 434→    if (item.id === '__calculator__' && calculatorResult) {
 435→      performCopy(calculatorResult, showHUD, {
 436→        hudIcon: <ClipboardHUDIcon />,
 437→        hudTitle: `Copied ${calculatorResult}`,
 438→      });
 439→      return;
 440→    }
 441→
 442→    const cmd = getCommand(item.id);
 443→
 444→    if (cmd?.component) {
 445→      addRecent(item.id);
 446→      push(cmd.name, {
 447→        type: 'command',
 448→        commandId: cmd.id,
 449→      });
 450→      setQuery('');
 451→      setSelectedIndex(0);
 452→    } else if (item.detail) {
 453→      push(item.title, {
 454→        type: 'detail',
 455→        item,
 456→      });
 457→      setQuery('');
 458→      showToast({
 459→        style: 'success',
 460→        title: `Opened ${item.title}`,
 461→      });
 462→    } else {
 463→      showToast({
 464→        style: 'success',
 465→        title: `Opened ${item.title}`,
 466→      });
 467→    }
 468→  }, [
 469→    allItems,
 470→    selectedIndex,
 471→    showToast,
 472→    showHUD,
 473→    calculatorResult,
 474→    push,
 475→    addRecent,
 476→  ]);
 477→
 478→  const toggleActions = useCallback(() => {
 479→    setActionsOpen(prev => !prev);
 480→  }, []);
 481→
 482→  const closeActions = useCallback(() => {
 483→    setActionsOpen(false);
 484→  }, []);
 485→
 486→  useKeyboardShortcut(
 487→    {
 488→      key: 'k',
 489→      meta: true,
 490→    },
 491→    toggleActions,
 492→    { enabled: !isFullView },
 493→  );
 494→
 495→  const handleToggleFavorite = useCallback(() => {
 496→    if (!selectedItem || selectedItem.id === '__calculator__') {
 497→      return;
 498→    }
 499→    const wasAlreadyFavorite = isFavorite(selectedItem.id);
 500→    toggleFavorite(selectedItem.id);
 501→    showHUD({
 502→      icon: <StarFilledIcon />,
 503→      title: wasAlreadyFavorite
 504→        ? 'Removed from Favorites'
 505→        : 'Added to Favorites',
 506→    });
 507→  }, [
 508→    selectedItem,
 509→    toggleFavorite,
 510→    isFavorite,
 511→    showHUD,
 512→  ]);
 513→
 514→  useKeyboardShortcut(
 515→    {
 516→      key: 'f',
 517→      meta: true,
 518→      shift: true,
 519→    },
 520→    handleToggleFavorite,
 521→    { enabled: isRoot && !!selectedItem },
 522→  );
 523→
 524→  const handleMoveFavoriteUp = useCallback(() => {
 525→    if (!selectedItem || !isFavorite(selectedItem.id)) return;
 526→    moveFavorite(selectedItem.id, 'up');
 527→    setSelectedIndex(prev => Math.max(0, prev - 1));
 528→  }, [
 529→    selectedItem,
 530→    isFavorite,
 531→    moveFavorite,
 532→  ]);
 533→
 534→  const handleMoveFavoriteDown = useCallback(() => {
 535→    if (!selectedItem || !isFavorite(selectedItem.id)) return;
 536→    moveFavorite(selectedItem.id, 'down');
 537→    setSelectedIndex(prev => prev + 1);
 538→  }, [
 539→    selectedItem,
 540→    isFavorite,
 541→    moveFavorite,
 542→  ]);
 543→
 544→  useKeyboardShortcut(
 545→    {
 546→      key: 'ArrowUp',
 547→      meta: true,
 548→      alt: true,
 549→    },
 550→    handleMoveFavoriteUp,
 551→    {
 552→      enabled: isRoot && !!selectedItem && isFavorite(selectedItem.id),
 553→    },
 554→  );
 555→
 556→  useKeyboardShortcut(
 557→    {
 558→      key: 'ArrowDown',
 559→      meta: true,
 560→      alt: true,
 561→    },
 562→    handleMoveFavoriteDown,
 563→    {
 564→      enabled: isRoot && !!selectedItem && isFavorite(selectedItem.id),
 565→    },
 566→  );
 567→
 568→  const openSettings = useCallback(() => {
 569→    const settingsCmd = getCommand('settings');
 570→    if (settingsCmd) {
 571→      const isAlreadySettings =
 572→        currentNavData?.type === 'command' &&
 573→        currentNavData.commandId === 'settings';
 574→      if (!isAlreadySettings) {
 575→        push('Settings', {
 576→          type: 'command',
 577→          commandId: 'settings',
 578→        });
 579→        setQuery('');
 580→        setSelectedIndex(0);
 581→        setActionsOpen(false);
 582→      }
 583→    }
 584→  }, [
 585→    currentNavData,
 586→    push,
 587→  ]);
 588→
 589→  useKeyboardShortcut(
 590→    {
 591→      key: ',',
 592→      meta: true,
 593→    },
 594→    openSettings,
 595→  );
 596→
 597→  const toggleQuickLook = useCallback(() => {
 598→    setQuickLookOpen(prev => !prev);
 599→  }, []);
 600→
 601→  const closeQuickLook = useCallback(() => {
 602→    setQuickLookOpen(false);
 603→  }, []);
 604→
 605→  useKeyboardShortcut(
 606→    {
 607→      key: 'y',
 608→      meta: true,
 609→    },
 610→    toggleQuickLook,
 611→    { enabled: isRoot && !!selectedItem?.detail },
 612→  );
 613→
 614→  useEffect(() => {
 615→    if (!isRoot || !selectedItem?.detail) return;
 616→
 617→    function handleSpaceBar(e: KeyboardEvent) {
 618→      if (e.key !== ' ' || e.metaKey || e.ctrlKey || e.altKey) {
 619→        return;
 620→      }
 621→      if (query !== '') return;
 622→
 623→      e.preventDefault();
 624→      e.stopPropagation();
 625→      setQuickLookOpen(prev => !prev);
 626→    }
 627→
 628→    window.addEventListener('keydown', handleSpaceBar);
 629→    return () => window.removeEventListener('keydown', handleSpaceBar);
 630→  }, [
 631→    isRoot,
 632→    selectedItem?.detail,
 633→    query,
 634→  ]);
 635→
 636→  const isCalculatorSelected = selectedItem?.id === '__calculator__';
 637→  const detail = isCalculatorSelected ? undefined : selectedItem?.detail;
 638→
 639→  const dropdownSections = useMemo(
 640→    () => [
 641→      {
 642→        title: 'Primary Actions',
 643→        actions: [
 644→          isCalculatorSelected && calculatorResult
 645→            ? createCopyAction(
 646→                {
 647→                  content: calculatorResult,
 648→                  title: 'Copy Result',
 649→                  shortcut: <Kbd keys={['↵']} />,
 650→                  hudIcon: <ClipboardHUDIcon />,
 651→                  hudTitle: `Copied ${calculatorResult}`,
 652→                },
 653→                showHUD,
 654→              )
 655→            : {
 656→                label: 'Open',
 657→                shortcut: <Kbd keys={['↵']} />,
 658→                onClick: () => {
 659→                  if (selectedItem) {
 660→                    showToast({
 661→                      style: 'success' as const,
 662→                      title: `Opened ${selectedItem.title}`,
 663→                    });
 664→                  }
 665→                },
 666→              },
 667→          {
 668→            label: 'Quick Look',
 669→            shortcut: (
 670→              <Kbd
 671→                keys={[
 672→                  '⌘',
 673→                  'Y',
 674→                ]}
 675→              />
 676→            ),
 677→            onClick: () => {
 678→              if (selectedItem?.detail) {
 679→                setActionsOpen(false);
 680→                setQuickLookOpen(prev => !prev);
 681→              }
 682→            },
 683→          },
 684→          ...(!isCalculatorSelected && selectedItem
 685→            ? [
 686→                {
 687→                  label:
 688→                    selectedItem && isFavorite(selectedItem.id)
 689→                      ? 'Remove from Favorites'
 690→                      : 'Add to Favorites',
 691→                  shortcut: (
 692→                    <Kbd
 693→                      keys={[
 694→                        '⌘',
 695→                        '⇧',
 696→                        'F',
 697→                      ]}
 698→                    />
 699→                  ),
 700→                  onClick: () => {
 701→                    if (selectedItem) {
 702→                      setActionsOpen(false);
 703→                      handleToggleFavorite();
 704→                    }
 705→                  },
 706→                },
 707→              ]
 708→            : []),
 709→        ],
 710→      },
 711→      {
 712→        title: 'Copy Actions',
 713→        actions: [
 714→          createCopyAction(
 715→            {
 716→              content: selectedItem?.title ?? '',
 717→              title: 'Copy Name',
 718→              shortcut: (
 719→                <Kbd
 720→                  keys={[
 721→                    '⌘',
 722→                    'C',
 723→                  ]}
 724→                />
 725→              ),
 726→            },
 727→            showHUD,
 728→          ),
 729→          {
 730→            label: 'Copy As...',
 731→            submenu: [
 732→              {
 733→                actions: [
 734→                  createCopyAction(
 735→                    {
 736→                      content: `**${selectedItem?.title ?? ''}**${selectedItem?.subtitle ? ` — ${selectedItem.subtitle}` : ''}`,
 737→                      title: 'Copy as Markdown',
 738→                      hudTitle: 'Copied as Markdown',
 739→                    },
 740→                    showHUD,
 741→                  ),
 742→                  createCopyAction(
 743→                    {
 744→                      content: JSON.stringify({
 745→                        title: selectedItem?.title,
 746→                        subtitle: selectedItem?.subtitle,
 747→                      }),
 748→                      title: 'Copy as JSON',
 749→                      hudTitle: 'Copied as JSON',
 750→                    },
 751→                    showHUD,
 752→                  ),
 753→                  createCopyAction(
 754→                    {
 755→                      content: selectedItem?.title ?? '',
 756→                      title: 'Copy as Plain Text',
 757→                      hudTitle: 'Copied as Plain Text',
 758→                    },
 759→                    showHUD,
 760→                  ),
 761→                ],
 762→              },
 763→            ],
 764→          },
 765→        ],
 766→      },
 767→      {
